function active$ElAccountByUnit(f) {f.add_onResponseComplete(on$ElAccountByUnit$ResponseComplete);}
function close$ElAccountByUnit(f) {try {f.remove_onResponseComplete(on$ElAccountByUnit$ResponseComplete)} catch (ex) {}}
function on$ElAccountByUnit$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'ma_dvcs');
      break;
    default:
      break;
  }
}      

      &ScriptIrregular;
